(window.webpackJsonp=window.webpackJsonp||[]).push([[1070],{1003:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">NumMatrix</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">__init__</span><span class=\\"hljs-params\\">(self, matrix)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type matrix: List[List[int]]\\n        \\"\\"\\"</span>\\n        m=len(matrix)\\n        <span class=\\"hljs-keyword\\">if</span> m==<span class=\\"hljs-number\\">0</span>:<span class=\\"hljs-keyword\\">return</span>\\n        n=len(matrix[<span class=\\"hljs-number\\">0</span>])\\n        sums=[[<span class=\\"hljs-number\\">0</span>]*n <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(m)]\\n        sums[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]=matrix[<span class=\\"hljs-number\\">0</span>][<span class=\\"hljs-number\\">0</span>]\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,m): sums[i][<span class=\\"hljs-number\\">0</span>]=sums[i<span class=\\"hljs-number\\">-1</span>][<span class=\\"hljs-number\\">0</span>]+matrix[i][<span class=\\"hljs-number\\">0</span>]\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,n): sums[<span class=\\"hljs-number\\">0</span>][i]=sums[<span class=\\"hljs-number\\">0</span>][i<span class=\\"hljs-number\\">-1</span>]+matrix[<span class=\\"hljs-number\\">0</span>][i]\\n        <span class=\\"hljs-keyword\\">for</span> i <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,m):\\n          <span class=\\"hljs-keyword\\">for</span> j <span class=\\"hljs-keyword\\">in</span> range(<span class=\\"hljs-number\\">1</span>,n):\\n            sums[i][j]=matrix[i][j]+sums[i<span class=\\"hljs-number\\">-1</span>][j]+sums[i][j<span class=\\"hljs-number\\">-1</span>]-sums[i<span class=\\"hljs-number\\">-1</span>][j<span class=\\"hljs-number\\">-1</span>]\\n        self.sums=sums\\n        <span class=\\"hljs-comment\\"># print sums</span>\\n\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">sumRegion</span><span class=\\"hljs-params\\">(self, row1, col1, row2, col2)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type row1: int\\n        :type col1: int\\n        :type row2: int\\n        :type col2: int\\n        :rtype: int\\n        \\"\\"\\"</span>\\n        dr1,dc1,dr2,dc2,p1,p2=row1<span class=\\"hljs-number\\">-1</span>,col2,row2,col1<span class=\\"hljs-number\\">-1</span>,row1<span class=\\"hljs-number\\">-1</span>,col1<span class=\\"hljs-number\\">-1</span>\\n        <span class=\\"hljs-keyword\\">if</span> dr1&lt;<span class=\\"hljs-number\\">0</span>: ds1=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">else</span>: ds1=self.sums[dr1][dc1]\\n        <span class=\\"hljs-keyword\\">if</span> dc2&lt;<span class=\\"hljs-number\\">0</span>: ds2=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">else</span>: ds2=self.sums[dr2][dc2]\\n        <span class=\\"hljs-keyword\\">if</span> p1&lt;<span class=\\"hljs-number\\">0</span> <span class=\\"hljs-keyword\\">or</span> p2&lt;<span class=\\"hljs-number\\">0</span>: ps=<span class=\\"hljs-number\\">0</span>\\n        <span class=\\"hljs-keyword\\">else</span>: ps=self.sums[p1][p2]\\n        <span class=\\"hljs-keyword\\">return</span> self.sums[row2][col2]-ds1-ds2+ps\\n        \\n\\n<span class=\\"hljs-comment\\"># Your NumMatrix object will be instantiated and called as such:</span>\\n<span class=\\"hljs-comment\\"># obj = NumMatrix(matrix)</span>\\n<span class=\\"hljs-comment\\"># param_1 = obj.sumRegion(row1,col1,row2,col2)</span>\\n</code></pre>\\n"],"titleSlug":"range-sum-query-2d-immutable","hasThinking":false,"content":"<p>\u7ed9\u5b9a\u4e00\u4e2a\u4e8c\u7ef4\u77e9\u9635\uff0c\u8ba1\u7b97\u5176\u5b50\u77e9\u5f62\u8303\u56f4\u5185\u5143\u7d20\u7684\u603b\u548c\uff0c\u8be5\u5b50\u77e9\u9635\u7684\u5de6\u4e0a\u89d2\u4e3a <code>(row1,\xa0col1)</code> \uff0c\u53f3\u4e0b\u89d2\u4e3a <code>(row2,\xa0col2)</code> \u3002</p>\\n\\n<p><img alt=\\"Range Sum Query 2D\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/images/304.png\\" style=\\"width: 130px;\\" /><br />\\n<small>\u4e0a\u56fe\u5b50\u77e9\u9635\u5de6\u4e0a\u89d2\xa0(row1, col1) = <strong>(2, 1)</strong>\xa0\uff0c\u53f3\u4e0b\u89d2(row2, col2) = <strong>(4, 3)\uff0c</strong>\u8be5\u5b50\u77e9\u5f62\u5185\u5143\u7d20\u7684\u603b\u548c\u4e3a 8\u3002</small></p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre>\\n\u7ed9\u5b9a matrix = [\\n  [3, 0, 1, 4, 2],\\n  [5, 6, 3, 2, 1],\\n  [1, 2, 0, 1, 5],\\n  [4, 1, 0, 1, 7],\\n  [1, 0, 3, 0, 5]\\n]\\n\\nsumRegion(2, 1, 4, 3) -> 8\\nsumRegion(1, 1, 2, 2) -> 11\\nsumRegion(1, 2, 2, 4) -> 12\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u4f60\u53ef\u4ee5\u5047\u8bbe\u77e9\u9635\u4e0d\u53ef\u53d8\u3002</li>\\n\\t<li>\u4f1a\u591a\u6b21\u8c03\u7528\xa0<code>sumRegion</code><em>\xa0</em>\u65b9\u6cd5<em>\u3002</em></li>\\n\\t<li>\u4f60\u53ef\u4ee5\u5047\u8bbe\xa0<code>row1 \u2264 row2</code> \u4e14\xa0<code>col1 \u2264 col2</code> \u3002</li>\\n</ul>\\n","title":"304. \u4e8c\u7ef4\u533a\u57df\u548c\u68c0\u7d22 - \u77e9\u9635\u4e0d\u53ef\u53d8","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["python"],"uniqueID":"304"}')}}]);